import throttle from 'lodash/throttle';

export default {
    props: {},
    components: {},
    mixins: [],
    data: function () {
        return {
            nameRegex: /^[a-zA-Z]+(([',. -][a-zA-Z ])?[a-zA-Z]*)*$/,
            phoneRegex: /^[+]*[(]{0,1}[0-9]{1,4}[)]{0,1}[-\s\\./0-9]*$/,
            emailRegex: /^(([^<>()\\[\]\\.,;:\s@"]+(\.[^<>()\\[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/,
            rules: {
                required: val => val && val.length > 0 || 'This field is required',
                name: val => this.nameRegex.exec(val) || 'Please enter a valid name',
                phone: val => val.length < 1 || this.phoneRegex.exec(val) || 'Please enter a valid phone number.',
                email: val => this.emailRegex.exec(val) || 'Please enter a valid email address',
            },
            form: {
                name: "",
                email: "",
                phone: "",
                enquiryMsg: "",
            },
            submitIsLoading: false,
        };
    },
    watch: {},
    computed: {},
    created: function () { },
    beforeDestroy: function () { },
    mounted: function () { },
    methods: {
        submitForm: function () {
            this.submitIsLoading = true;
            let message = `>>> **Name:** ${this.form.name}\n` +
                `**Email:** ${this.form.email}\n` +
                `**Phone:** ${this.form.phone}\n` +
                `**Message:**\n${this.form.enquiryMsg}`

            
            try {
                this.sendMessage(message);
                this.$q.notify({
                    message: 'Thanks you, the enquiry is sent successfully',
                    color: 'green'
                });
            } catch (error) {
                this.$q.notify({
                    message: 'Something went wrong, please try to contact me via email.',
                    color: 'red-7'
                });
            }
            this.submitIsLoading = false;
            this.$emit("closeDialog");
        },
        sendMessage: throttle(function (msg) {
            let request = new XMLHttpRequest();
            let webhookURL = "https://discordapp.com/api/webhooks/688308180647804928/iRLOmorJTuEkpn_qcbuOCB_fm5o8Ne6V5G3GJ4mF5zxd4wcqCJYC3tQyKL2dsqQ-9DeT";
            request.open("POST", webhookURL);

            request.setRequestHeader('Content-type', 'application/json');

            var params = {
                username: "Portfolio Enquiry",
                avatar_url: "",
                content: msg
            }

            if(request.send(JSON.stringify(params))){
                return true;
            }
        }, 60000, { 'trailing': false })
    },
}
